INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6f0ba476-moex-00235', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初以8千萬元購入1棟耐用年限40年之房屋，殘值為零，採直線法折舊（若 有需要時）。公司之會計政策為自用不動產採重估價模式並於每年底進行重估價，投資性不動 產採公允價值模式。該房屋於X1及X2年底之公允價值分別為8千2百萬元及8千6百萬 元，甲公司於第2年底進行重估後立即出售該房屋。請問甲公司若將此房屋歸類為自用不動 產或投資性不動產，對淨利與淨值之影響為何？', '["自用不動產下之X1年度淨利及淨值都將低於投資性不動產", "自用不動產下之X2年度淨利及淨值都將等於投資性不動產", "自用不動產下之X1年度淨利將高於投資性不動產，惟淨值將等於投資性不動產", "自用不動產下之X2年度淨利將低於投資性不動產，惟淨值將等於投資性不動產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00236', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '以間接法編製現金流量表時，關於「存貨跌價損失」此損益項目之處理何者正確？', '["若以存貨淨額評估增減變動數時，本期淨利應加回存貨跌價損失", "若以存貨淨額評估增減變動數時，本期淨利應扣除存貨跌價損失", "若以存貨總額評估增減變動數時，本期淨利無須調整存貨跌價損失", "若以存貨總額評估增減變動數時，本期淨利應加回存貨跌價損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00237', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司董事會於X1年11月規劃處分童裝部門，惟尚未作成最後決定。已知童裝部門當年度 營業利益為$300,000，X1年底淨資產之帳面金額為$600,000，X1年底淨資產之公允價值減出 售成本金額為$540,000。X2年1月中，公司董事會核准並宣布開始執行處分童裝部門，童裝 部門X2年4月底以$510,000處分該部門，當時淨資產之帳面金額為$540,000。X2年度童裝 部門營業損失$120,000。假設所得稅稅率為17%，試問甲公司X2年損益表中列示之停業單位 損益為何？', '["$0", "$(24,900)", "$(99,600)", "$(124,500)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00238', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司買入土地作為自用工廠用地，後續衡量採用重估價模式。若當年度該土地有公允價值 變動之增值利益，且依稅法規定土地之增值利益於出售時始需課稅，關於該增值利益對甲公 司財務報表之影響，下列敘述何者正確？', '["計入本期淨利之所得稅費用增加、保留盈餘增加", "計入本期淨利之所得稅費用增加、本期其他綜合淨利增加", "遞延所得稅負債增加、其他權益增加", "本期所得稅負債增加、本期綜合淨利增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00239', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '乙公司X5年12月31日報表中有總資產$2,800,000，負債僅有下列2筆：⑴X5年8月1日 發行9個月期商業本票面額$636,000，有效利率為8%。⑵X5年9月1日向銀行借入$500,000， 6個月到期時付息還本，利率6%。試問X5年12月31日乙公司負債對資產比為多少？（答 案四捨五入至小數點第4位）', '["40.36%", "40.57%", "40.93%", "41.69%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00240', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X7年初以繼續服務滿3年為條件，給予1位高階主管1項權利，可選擇取得相當 於1,000股股票之現金，或1,200股面額$10之普通股。若選擇領取股票，則於既得日後2年 內不得出售，給與日之股價為每股$42。考慮既得日後限制2年內不得出售之效果，估計該限 制股票於給與日之公允價值為$39。甲公司X7年、X8年、X9年年底股價分別為$45、$48及 $52，且預期未來3年不會發放股利。試問甲公司X8年應認列薪資費用為何？', '["$15,600", "$16,400", "$18,600", "$19,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00241', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '乙公司有關確定福利計畫的相關資料如下：X3 年初確定福利義務現值為$850,000，X3 年初 確定福利計畫修改產生正數的前期服務成本$150,000，X3年度產生當期服務成本$152,000、 提撥計畫資產$151,000、支付退休金$510,000、精算損失$105,000與確定福利計畫資產實際報 酬$80,000。X3年度折現率為12%。請問乙公司X3年12月31日確定福利義務現值為何？', '["$867,000", "$524,000", "$731,000", "$628,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00242', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X1年度綜合損益表中之本期淨利$2,012,024，綜合損益總額為$3,018,036（利益）。甲 公司於X1年初流通在外普通股股數為100,000股，4月1日現金增資發行新股20,000股，7 月1日發放24,000股股票股利，10月1日購買庫藏股20,000股。則綜合損益表中所表達之 基本每股盈餘為何？', '["$15.128", "$16.226", "$16.492", "$24.339"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00243', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '乙公司採曆年制，於X2年10月15日以每股$50買入丁公司股票1,000股，手續費$100，分 類為透過其他綜合損益按公允價值衡量之金融資產。X2年12月31日丁公司收盤價為$46， X3年8月15日收到現金股利每股$2，股票股利10%。X3年10月1日將丁公司股票以每股 $48全數賣出。關於該投資對X3年度乙公司綜合損益表之影響，下列敘述何者正確？', '["本期淨利中有處分金融資產利益$2,000", "本期淨利中有處分金融資產利益$2,700", "其他綜合損益中有透過其他綜合損益按公允價值衡量股票投資未實現利益$2,700", "其他綜合損益中有透過其他綜合損益按公允價值衡量股票投資未實現利益$6,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00244', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '對按攤銷後成本衡量且購入或創始時並非已信用減損之債券投資，下列有關其預期信用損失 之敘述何者正確？', '["預期信用損失乃是指合約現金短收合計數", "若自原始認列後信用風險沒有顯著增加，則按「12個月預期信用損失」衡量", "企業應在有客觀證據顯示有減損跡象時，才須認列預期信用損失", "若金融資產自原始認列後信用風險已有顯著增加，則按「16個月預期信用損失」衡量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
